mapper.select:
select univ_id , univ_nm , univ_ticket from p_univ pu where 1=1
AND pu.univ_nm like '%${schText}%'
LIMIT #{paginationInfo.firstRecordIndex}, #{recordsPerPage}

mapper.update:
		UPDATE p_univ
		SET univ_nm = #{univNm}
        , univ_ticket = #{univTicket}
		WHERE 1=1
		AND univ_id = #{univId}

mapper.delete:
		DELETE FROM p_univ
		WHERE 1=1
        AND univ_id = #{univId}

mapper.update:
UPDATE p_univ
SET univ_ticket = univ_ticket + #{addTicket}
WHERE 1=1
AND univ_id = #{univId}

UPDATE p_univ
SET univ_ticket = univ_ticket - #{minusTicket}
WHERE 1=1
AND univ_id = #{univId}
